 WEB: APACHE 2.4 o superior\\r\\n• PANEL DE CONTROL: SI\\r\\n• PÁGINAS QUE SOPORTA: HTML, .HTM,\\r\\nPHP, .JAVA, FLASH\\r\\n• BASE DE DATOS: MySql 15.1 Distrib\\r\\n10.3.17 –Mariadb para Linux o superior\\r\\n• NÚMERO DE BASE DE DATOS: 1\\r\\n• ACCESO VÍA FTP: SI\\r\\n• NRO. CUENTAS FTP: 1\\r\\n• ESPACIO EN DISCO: 10 GB\\r\\n• ESTADÍSTICAS DE NAVEGACIÓN DEL\\r\\nSITIO: SI\"}','190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 13:15:35'),(83,1,1,'VIEW','procesos',6,NULL,NULL,'190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 13:15:35'),(84,1,1,'VIEW','procesos',6,NULL,NULL,'190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 13:17:13'),(85,1,1,'CREATE','instituciones',5,NULL,'{\"nombre\": \"FISCALIA DE MANABI\"}','190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 13:19:36'),(86,1,1,'CREATE','procesos',7,NULL,'{\"numero\": \"NIC-1360055450001-2026-00002\"}','190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 13:19:36'),(87,1,1,'VIEW','procesos',7,NULL,NULL,'190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 13:19:36'),(88,1,1,'VIEW','procesos',7,NULL,NULL,'190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 15:19:26'),(89,1,1,'VIEW','procesos',7,NULL,NULL,'190.11.14.57','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36','2026-03-09 15:26:42'),(90,1,1,'UPDATE','procesos',7,'{\"id\": 7, \"cpc\": 