--
-- Table structure for table `dominios`
--

DROP TABLE IF EXISTS `dominios`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dominios` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `tenant_id` int unsigned NOT NULL,
  `institucion_id` int unsigned NOT NULL,
  `dominio` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tld` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ec' COMMENT 'ec, com, net, org, gob.ec, edu.ec ...',
  `dominio_completo` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'dominio + tld ej: miempresa.ec',
  `fecha_registro` date DEFAULT NULL,
  `fecha_caducidad` date DEFAULT NULL,
  `fecha_ultimo_cambio` date DEFAULT NULL,
  `titular` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Nombre del titular según RDAP',
  `registrador` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Registrar/proveedor',
  `nameservers` text COLLATE utf8mb4_unicode_ci COMMENT 'JSON array de nameservers',
  `estado_rdap` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'active, expired, etc.',
  `ultima_consulta_rdap` datetime DEFAULT NULL,
  `estado` enum('activo','vencido','por_vencer','suspendido','cancelado') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'activo',
  `dias_alerta` tinyint unsigned NOT NULL DEFAULT '30' COMMENT 'Alertar X días antes del vencimiento',
  `renovacion_auto` tinyint(1) NOT NULL DEFAULT '0',
  `costo_renovacion` decimal(8,2) DEFAULT NULL,
  `notas` text COLLATE utf8mb4_unicode_ci,
  `rdap_raw` mediumtext COLLATE utf8mb4_unicode_ci COMMENT 'JSON crudo de la última consulta RDAP',
  `deleted_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_institucion` (`institucion_id`),
  KEY `idx_caducidad` (`fecha_caducidad`),
  KEY `idx_estado` (`estado`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `dominios`
--

