INSERT INTO `proceso_items` VALUES (1,1,14,1,'352901091','INSUMOS DE USO GENERAL','YODOPOVIDONA GALON\nCONCENTRACIÓN: 10% povidona yodada\nPRESENTACIÓN: Galón\nUNIDAD DE MEDIDA: Galón','Unidad',1.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(2,1,14,2,'352901091','INSUMOS DE USO GENERAL','DEPRESOR PARA LA LENGUA, ESTÉRIL\nMATERIAL: Madera con superficie lisa, sin astillas y sin olor/sabor\nDIMENSIONES\nESTÁNDAR: Aproximadamente 150 mm largo x 18-20 mm ancho x 1,5-2 mm espesor\nFORMA: Plana, con bordes redondeados y extremos lisos.\nUNIDAD DE MEDIDA: Unidad','Unidad',500.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(3,1,14,3,'352901091','INSUMOS DE USO GENERAL','ESPARADRAPO ANCHO DE TELA NO TEJIDA TRANSPIRABLE CINTA DE ALGODÓN\nMATERIAL: Adhesivo Hipo alergénico, libre de látex\nTRANSPIRABILIDAD: Alta permeabilidad al vapor de agua y aire.\nPRESENTACIÓN: Rollos de gran anchura\nCOLOR: Blanco.\nADAPTABILIDAD: Flexible para zonas anatómicas difíciles.\nRASGADO: Fácil rasgado manual.\nUNIDAD DE MEDIDA: Unidad','Unidad',2.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(4,1,14,4,'352901091','INSUMOS DE USO GENERAL','ESPARADRAPO COMÚN 8 CM X 9.1 M\nMATERIAL: Tela algodón o material hipo alergénico 8 CM X 9.1 M\nADHESIVO: Óxido de zinc, resinas, y/o adhesivo de acrilato.\nCOLOR: Blanco.\nPROPIEDADES: Impermeable, transpirable, alta resistencia a la tracción\nUSO: Descartable/Un solo uso.\nFUNCIONES: Fijación de apósitos, gasas, sondas, cánulas y catéteres.\nUNIDAD DE MEDIDA: Unidad','Unidad',7.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(5,1,14,5,'352901091','INSUMOS DE USO GENERAL','GUANTES DE EXAMINACIÓN, TALLA GRANDE, NITRILO\nMaterial: 100% Nitrilo sintético (acrilonitrilo-butadieno).\nTALLA: Grande (Large - L).\nDISEÑO: Ambidiestro\ncon borde enrollado (puño reforzado).\nSUPERFICIE: Microtexturizada en la punta de los dedos para mejor agarre.\nESPESOR: Rango típico de 3.5 a 6 mil (aprox. 0.08 mm - 0.15 mm)\nLARGO: Mínimo 240 mm (estándar de examinación).\nESTERILIDAD: No estériles.\nPOLVO: Libre de polvo (sin polvo absorbente).\nUNIDAD DE MEDIDA: Caja x 50 Unidades','Unidad',36.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(6,1,14,6,'352901091','INSUMOS DE USO GENERAL','GUANTES DE EXAMINACIÓN, TALLA GRANDE, LÁTEX\nMATERIAL: 100% látex de caucho natural de alta calidad.\nTALLA: Grande L, con una circunferencia de mano adecuada (L: 229 mm).\nDISEÑO: Ambidiestro, puño con borde enrollado para mayor resistencia.\nRESISTENCIA Y CALIDAD: Cumple con la norma ASTM D3578 y AQL 1.5 o 5.0 (nivel de calidad aceptable).\nLONGITUD: Mínimo 230 mm - 240 mm.\nCOLOR: Blanco natural.\nESTERILIDAD: No estériles.\nUNIDAD DE MEDIDA: Caja x 50 Unidades','Unidad',25.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(7,1,14,7,'352901091','INSUMOS DE USO GENERAL','HOJAS DE BISTURÍ #20\nMATERIAL: Acero de carbono o Acero inoxidable.\nCOMPATIBILIDAD: Se adaptan a mangos de bisturí estándar número 4.\nESTERILIZACIÓN: Esterilizadas por Rayos\nGamma\nFORMA: Hoja grande con borde cortante curvo hasta la punta.\nUSO: Quirúrgico, desechable.\nUNIDAD DE MEDIDA: Unidad','Unidad',30.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(8,1,14,8,'352901091','INSUMOS DE USO GENERAL','GASA VASELINADA SOBRES\nCOMPOSICIÓN: Malla de gasa de algodón de baja adherencia, impregnada con parafina suave o vaselina blanca.\nESTRUCTURA: Malla de tejido abierto para permitir el libre paso del exudado hacia un apósito secundario.\nEMPAQUE: Sobres individuales con recubrimiento metalizado interno para preservar la humedad y evitar que se seque.\nCARACTERÍSTICAS FÍSICAS: No tóxica, libre de látex, de un solo uso.\nFUNCIÓN: Reduce el dolor en los cambios de apósito, efecto calmante, biodegradable.\nUNIDAD DE MEDIDA: Unidad','Unidad',20.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(9,1,14,9,'352901091','INSUMOS DE USO GENERAL','TORNIQUETE TÁCTICO\nalta resistencia, barra de molinete de plástico rígido/aluminio, y sistema de velcro.\nPESO: 80g y 110g\nDIMENSIONES PLEGADO:\n16-18 cm x 5-6 cm x 4 cm\nDIMENSIONES DESPLEGADO: longitud 95-96 cm\nCOMPONENTES: Banda de tiempo, molinete (varilla), clip de bloqueo del molinete, banda de\nvelcro y hebilla de enrutamiento.\nUNIDAD DE MEDIDA: Unidad','Unidad',2.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(10,1,14,10,'352901091','INSUMOS DE USO GENERAL','BOLSA TÁCTICA MILITAR PARA MUSLO\nMATERIAL: Nailon 1000D o 700D de alta densidad, resistente al agua y a la abrasión.\nDIMENSIONES COMUNES: Aproximadamente\nde alto 20-30 cm y 10-15 de ancho x 10 cm de profundidad.\nESTRUCTURA:\nCompartimentos principales con cremalleras de alta resistencia (metálicas o de doble costura).\nSISTEMA DE AJUSTE:\nCorrea de cintura ajustable\nCorrea de muslo ajustable y desmontable\nUNIDAD DE MEDIDA: Unidad','Unidad',2.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(11,1,14,11,'352901091','INSUMOS DE USO GENERAL','LLAVE DE 3 Vías\nMATERIAL: Cuerpo de policarbonato (PC) transparente y manilla de polietileno de alta densidad (HDPE), resistente a lípidos y fármacos.\nCONEXIONES: Sistema Luer Lock universal\nSEGURIDAD: Tapas de protección, libre de látex, apirógeno y esterilizado con Óxido de Etileno (EO).\nFUNCIONALIDAD: Giro de 360 grados, manilla con flechas indicadoras de flujo, permite cierre de vías.\nEXTENSIÓN: Disponible con o sin tubo de extensión de PVC (flexible, transparente)\nde diversas longitudes (10cm - 100cm).\nUSO: Dispositivo de un solo uso.\nUNIDAD DE MEDIDA: Unidad','Unidad',50.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(12,1,14,12,'352901091','INSUMOS DE USO GENERAL','CABESTRILLO SIMPLE TALLA MEDIANA\nTELA DE ALGODÓN CON DISEÑO EN FORMA DE BOLSA QUE PERMITE SOSTENER EL BRAZO A LA ALTURA DEL PECHO A 90 GRADOS EN RELACIÓN CON EL HOMBRO. PARA USO EN POST OPERATORIOS Y TRAUMAS DE LA MANO, BRAZO Y MUÑECA Y PARA EL DESCANSO DE BRAZO ENYESADO. TAMAÑO AJUSTABLE\nUNIDAD DE MEDIDA: Unidad','Unidad',2.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(13,1,14,13,'352901091','INSUMOS DE USO GENERAL','MASCARILLA QUIRÚRGICA PARA ADULTO\nMASCARILLA QUIRÚRGICA RECTANGULAR DE 3 PLIEGUES\nESTÉRILES DESECHABLE PLANA CON TIRAS ELÁSTICAS DE SUJECIÓN.\nPROTECCIÓN DE NARIZ Y BOCA PARA MINIMIZAR CONTACTOS INFECCIOSOS EN LOS MEDIOS QUIRÚRGICOS, Y DEMÁS AMBIENTES ESTÉRILES O SENSIBLES.\nTRES CAPAS DE TELA NO TEJIDA, QUE PERMITE UNA PERFECTA VENTILACIÓN\nUNIDAD DE MEDIDA: Unidad','Unidad',2500.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(14,1,14,14,'352901091','INSUMOS DE USO GENERAL','CURITAS\nMATERIAL: red de polietileno, adhesivo disolvente, papel de silicona, almohadilla absorbente no tejida, envoltura de papel\nUNIDAD DE MEDIDA: Unidad','Unidad',200.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(15,1,14,15,'352901091','INSUMOS DE USO GENERAL','PLICOMETRO\nMATERIAL: Plástico ABS de alta resistencia o plástico de ingeniería.\nRANGO DE MEDICIÓN: 0 - 50 mm, 0-60 mm o hasta 80 mm.\nRESOLUCIÓN/PRECISIÓN: 0.5 mm o 1 mm.\nDIMENSIONES: Aproximadamente 16.5 x 10 cm o hasta 27 cm en modelos tipo pistola.\nPESO: Muy ligero, a menudo alrededor de 20-120 gramos.\nUNIDAD DE MEDIDA: Unidad','Unidad',2.0000,0.0000,0.0000,'2026-03-10 21:40:20','2026-03-10 21:39:57','2026-03-10 21:40:20'),(16,1,14,16,'352901091','INSUMOS DE USO GENERAL','JERINGUILLA DE 3ML X1 CAJAX100\nCAPACIDAD: 3 ml / 3 cc.\nPRESENTACIÓN: Caja x 100 unidades.\nESTRUCTURA: Tres partes cuerpo, pistón y embolo de goma.\nMATERIAL: Plástico grado médico, libre de látex, atóxico y apirogénico.\nAGUJA: Incluid