INSERT INTO `procesos` VALUES (1,1,'NIC-1768107770001-2026-00008','infima_cuantia','CONTRATACIÓN DE REACTIVACIÓN, REDISEÑO, HOSTING, DOMINIO Y ADMINISTRACIÓN DE LA PÁGINA WEB, PARA EL GAD PARROQUIAL TOCACHI',NULL,NULL,NULL,'<figure class=\"table\"><table><tbody><tr><td>Nº</td><td>DESCRIPCION</td><td>CANTIDAD</td></tr><tr><td>&nbsp;</td><td>Contratación deServicios para&nbsp;la&nbsp;renovación de hosting, dominio,&nbsp;mantenimiento&nbsp;de la&nbsp;página&nbsp;web&nbsp;institucional (licencia&nbsp;anual)&nbsp;del&nbsp;Gobierno&nbsp;Autónomo&nbsp;Descentralizado parroquial&nbsp;de Bulán-Cantón&nbsp;Paute-Provincia del&nbsp;Azuay &nbsp;<a href=\"https://gadbulan.gob.ec/azuay/\">https://gadbulan.gob.ec/azuay/</a></td><td rowspan=\"8\"><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>1</p></td></tr><tr><td>&nbsp;</td><td><p>&nbsp;</p><p>Con &nbsp;esta &nbsp;contratación &nbsp;de &nbsp;servicio, &nbsp;nuestra &nbsp;Institución requiere&nbsp;que&nbsp;los&nbsp;iconos&nbsp;de&nbsp;las&nbsp;tareas&nbsp;principales&nbsp;del&nbsp;sitio</p></td></tr><tr><td>&nbsp;</td><td>web&nbsp; &nbsp; &nbsp;tengan&nbsp; &nbsp; &nbsp;un&nbsp; &nbsp;&nbsp;diseño&nbsp; &nbsp;&nbsp;de&nbsp; &nbsp;&nbsp;buen&nbsp; &nbsp;&nbsp;contenido,</td></tr><tr><td>&nbsp;</td><td>modernización &nbsp;y &nbsp;colores &nbsp;acordes &nbsp;a &nbsp;nuestra &nbsp;imagen</td></tr><tr><td>&nbsp;</td><td>institucional&nbsp; &nbsp;pudiendo&nbsp; &nbsp;ser&nbsp; &nbsp;&nbsp;cambiados&nbsp; &nbsp;en&nbsp; &nbsp;cualquier</td></tr><tr><td>&nbsp;</td><td>momento&nbsp;sin&nbsp; generar &nbsp;cargos&nbsp;o&nbsp;facturas &nbsp;adicionales&nbsp; &nbsp;al valor&nbsp;contratado&nbsp;de manera&nbsp;anual.</td></tr><tr><td>&nbsp;</td><td><p>&nbsp;</p><p>Uso&nbsp;activo&nbsp;de los servicios de&nbsp;la&nbsp;página web.</p></td></tr><tr><td>&nbsp;</td><td><p>&nbsp;</p><p>•&nbsp;Uso&nbsp;de&nbsp;correo&nbsp;institucional.</p><p>•&nbsp;Espacio&nbsp;Ilimitado.</p><p>•&nbsp;Transferencia&nbsp;ILIMITADA.</p><p>•&nbsp;Cuentas Correo&nbsp;ilimitadas.</p><p>•&nbsp;Bases de&nbsp;Datos Ilimitadas.</p><p>•&nbsp;DominiosIlimitados.</p><p>•&nbsp;Parking&nbsp;Ilimitado.</p><p>•&nbsp;Servicios brindados:</p><p>o&nbsp;Restauración ygeneración&nbsp;de&nbsp;respaldos.</p><p>o&nbsp;Actualizaciones&nbsp;de&nbsp;PHP,&nbsp;Mysql sistema&nbsp;preinstalado.</p><p>o&nbsp;CompilaciónPHP&nbsp;y&nbsp;optimizaciónMySQL.&nbsp;o</p><p>Configuración&nbsp;de DNS&nbsp;personalizada.</p><p>o&nbsp;Solución de&nbsp;problemas&nbsp;de&nbsp;FTP,&nbsp;sobre&nbsp;carga&nbsp;de servidor.</p></td></tr></tbody></table></figure><p>&nbsp;</p><p>&nbsp;</p><p><br>&nbsp;</p><p>&nbsp;</p>',1,NULL,'<p>METODOLOGIA DE&nbsp;TRABAJO</p><p>Para&nbsp; el &nbsp;presente&nbsp;procedimiento&nbsp;de &nbsp;contratación&nbsp; se&nbsp;lo&nbsp;realizará&nbsp; por&nbsp;ÍNFIMA CUANTÍA; a&nbsp;través&nbsp;del&nbsp;aplicativo&nbsp;Necesidades&nbsp;de&nbsp;Ínfima&nbsp;Cuantía&nbsp;establecido&nbsp;por el&nbsp;SERCOP,&nbsp;donde&nbsp;los&nbsp;proveedores&nbsp;deberán&nbsp;presentar&nbsp;las&nbsp;respectivas&nbsp;proformas, de la&nbsp;cual&nbsp;se elegirá&nbsp;la&nbsp;mejor opción&nbsp;para la&nbsp;institución.</p><p>El&nbsp;proveedor&nbsp;que resulte&nbsp;ganador&nbsp;brindará&nbsp;el&nbsp;servicio&nbsp;para&nbsp;la&nbsp;renovación&nbsp;de Hosting, dominio,&nbsp;mantenimiento&nbsp;de&nbsp;la&nbsp;página Web&nbsp;institucional&nbsp;(Licencia&nbsp;anual) (gadbulan.gob.ec)&nbsp;del&nbsp;Gobierno&nbsp;Autónomo&nbsp;Descentralizado&nbsp;Parroquial&nbsp;de Bulán del&nbsp;Cantón&nbsp;Paute-Provincia del&nbsp;Azuay.</p>','60 dias ',NULL,1,525.00,NULL,'USD',10,'El plazo será a partir de la aceptación de la orden de compra por el proveedor hasta su entrega total con lo cual se dará por terminado automáticamente, sin necesidad de notificación alguna, misma que se suscribirá entre la máxima autoridad y el proveedor seleccionado en el proceso de contratación por Ínfima cuantía publicada en el Portal de Compras Públicas.\r\n\r\n\r\nEl plazo de duración del presente servicio es de 12 meses (año calendario)\r\ncontado a partir de la suscripción de la orden de compra.\r\n','<p>El&nbsp;pago se&nbsp;realizará&nbsp;mediante&nbsp;el&nbsp;Sistema&nbsp;de Pagos&nbsp;Interbancario&nbsp;SPI,&nbsp;posterior&nbsp;a la entrega del&nbsp;servicio solicitado,&nbsp;y&nbsp;la&nbsp;emisión&nbsp;de&nbsp;la&nbsp;factura&nbsp;correspondiente.</p>','2026-03-06',NULL,NULL,'adjudicado',2,0.00,0,NULL,0,365,NULL,NULL,NULL,NULL,1,NULL,'2026-03-10 22:54:15','2026-03-06 23:39:31','2026-03-10 22:54:15',NULL,1),(2,1,'NIC-1260032500001-2026-00011','infima_cuantia','CONTRATACION DE LA RENOVACION DEL HOSTING, DOMINIO Y ACTUALIZACION DEL SITIO WEB DEL GAD PARROQUIAL BARRAGANETE',NULL,NULL,NULL,'<p><strong>PRODUCTOS O SERVICIOS ESPERADOS</strong></p><p>El GAD Parroquial Rural de Bulán requiere hacer la contratación del siguiente servicio:</p><p>Nº DESCRIPCION CANTIDAD</p><p>1</p><p>Contratación de Servicios para la renovación de hosting, dominio, mantenimiento de la página web institucional (licencia anual) del Gobierno Autónomo Descentralizado parroquial de Bulán-Cantón Paute-Provincia del Azuay https://gadbulan.gob.ec/azuay/</p><p>Con esta contratación de servicio, nuestra Institución requiere que los iconos de las tareas principales del sitio web tengan un diseño de buen contenido, modernización y colores acordes a nuestra imagen institucional pudiendo ser cambiados en cualquier momento sin generar cargos o facturas adicionales al valor contratado de manera anual.</p><p>Uso activo de los servicios de la página web.</p><ul><li>Uso de correo institucional.</li><li>Espacio Ilimitado.</li><li>Transferencia ILIMITADA.</li><li>Cuentas Correo ilimitadas.</li><li>Bases de Datos Ilimitadas.</li><li>Dominios Ilimitados.</li><li>Parking Ilimitado.</li><li>Servicios brindados:</li><li>Restauración y generación de respaldos.</li><li>Actualizaciones de PHP, Mysql sistema preinstalado.</li><li>Compilación PHP y optimización MySQL.</li><li>Configuración de DNS personalizada.</li><li>Solución de problemas de FTP, sobre carga de servidor.</li><li>Sustitución de hardware.</li><li>Recuperación de servidor y restauración de disco duro.</li><li>Instalación y configuración de Software Firewall.</li><li>Asistencia en reparación de base de datos corrompida.</li><li>Asistencia respecto alertas y advertencias del sistema.</li></ul><p><strong>MANTENIMIENTO DE PAGINA WEB Actualización Diseño de Pagina Web</strong> La actualización del diseño web debe ser creativa, original, funcional y con diseños personalizados, adaptados a un giro institucional y las necesidades del entorno digital. Lenguaje de programación a la versión actual, implica protocolos y códigos que se renuevan constantemente dentro de la estructura de un sitio web. Dentro de los servicios al dar mantenimiento a una página web, van un poco más allá del mantenimiento preventivo que ofrecen beneficios adicionales, tales como soporte ante algún incidente u horas técnicas que se utilicen para mejorar el sitio; como, por ejemplo:</p><ul><li>Rediseño Responsivo</li><li>Implementación de Tickets para breve atención con los usuarios</li><li>Implementación de Facebook, Twitter, Instagram y WhatsApp</li><li>Accesibilidad web para grupos vulnerables</li><li>Optimizado para buscadores</li><li>Creación de correos Institucionales que se solicite</li><li>Soporte técnico permanente</li><li>Monitoreo constante de seguridades web</li><li>Respaldos semanales del sitio</li><li>Actualización de la plataforma web</li><li>Actualización de plugins y herramientas</li><li>Renovación anual de Hosting y dominio.gob.ec</li><li>Creación de pestañas de Transparencia y Rendición de Cuentas anual</li><li>Creación de nuevas pestañas</li><li>Subida y actualización de noticias cuando se solicite</li><li>Subida y actualización de información y documentos</li><li>Capacitación virtual del Sitio Web</li><li>Repotenciación de Protección de Amenazas</li><li>Seguridad de la página web ante ataques a la base de datos.</li><li>Protección para autenticación fraudulenta, ante los inicios de sesión contra piratas informáticos que buscan robar credenciales y contraseñas.</li><li>Aplicación de cross-site scripting o secuencias de comando entre sitios (XSS), ante scripts maliciosos que atacan sitios web de buena reputación y confiables.</li></ul><p><strong>Realización de Copias de Seguridad</strong> Contar con un backup o copia de seguridad de nuestro site-web, en la que quede disponible toda la información para recuperarla en caso de daños, y la organización de la base de datos que contengan codificaciones y programaciones, indispensables para la ejecución de las herramientas que se encuentran subidas como aplicativos en la web.</p><p>Además de lo mencionado el Contenido en hojas el que se necesite:</p><p>Galería de productos y fotos</p><ul><li>Lista de Videos YouTube</li><li>Conexión con redes.</li><li>Formulario de contáctenos</li><li>Accesos a las redes sociales</li><li>El proveedor deberá asumir los costos adicionales, de cambio de dominio y respaldo de toda la información que existe en la página web institucional.</li></ul>',1,NULL,'<p>Para el presente procedimiento de contratación se lo realizará por ÍNFIMA CUANTÍA; a través del aplicativo Necesidades de Ínfima Cuantía establecido por el SERCOP, donde los proveedores deberán presentar las respectivas proformas, de la cual se elegirá la mejor opción para la institución. El proveedor que resulte ganador brindará el servicio para la renovación de Hosting, dominio, mantenimiento de la página Web institucional (Licencia anual) (gadbulan.gob.ec) del Gobierno Autónomo Descentralizado Parroquial de Bulán del Cantón Paute-Provincia del Azuay.</p>','60 dias','<p>Con la contratación de los servicios para hosting, dominio, mantenimiento de la página web institucional (licencia anual) del Gobierno Autónomo Descentralizado Parroquial de Bulán https://gadbulan.gob.ec se busca que la página web institucional del Gobierno Parroquial de Bulán contenga los ítems que dispone el artículo 7 la Ley Orgánica de Transparencia y Acceso a la Información Pública y la Ley Orgánica del Consejo de Participación Ciudadana y Control Social y de esta forma la ciudadanía pueda acceder a la información referente al servicio que brinda nuestra Institución. Así mismo se busca proveer a las autoridades, personal administrativo y a la comunidad herramientas web que permitan un mejor uso de los recursos, servicios y tiempo de respuesta en el marco de un desarrollo óptimo institucional y parroquial.</p>',2,620.00,NULL,'USD',365,'10 dias','<p>en transfecnai SP1</p>','2026-03-07',NULL,NULL,'en_ejecucion',2,0.00,0,NULL,0,365,NULL,NULL,NULL,NULL,1,NULL,'2026-03-10 22:54:06','2026-03-07 16:06:24','2026-03-10 22:54:06','cumplimos ',1),(3,1,'NIC-1260032500001-2026-00011','otro','CONTRATACION DE LA RENOVACION DEL HOSTING, DOMINIO Y ACTUALIZACION DEL SITIO WEB DEL GAD PARROQUIAL BARRAGANETE','',NULL,NULL,'',1,NULL,'',NULL,NULL,2,520.00,NULL,'USD',10,NULL,NULL,'2026-03-07',NULL,NULL,'adjudicado',1,0.00,0,NULL,0,365,NULL,NULL,NULL,NULL,1,NULL,'2026-03-09 02:57:39','2026-03-07 17:17:45','2026-03-09 02:57:39',NULL,1),(4,1,'NIC-1060041880001-2026-00006','infima_cuantia','CONTRATACIÓN DEL SERVICIO DE HOSTING, NOMBRE DE DOMINIO, CORREO INSTITUCIONAL, MANEJO Y MANTENIMIENTO DE LA PÁGINA WEB INSTITUCIONAL DEL CUERPO DE BOM','979901011',NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,3,0.00,NULL,'USD',0,NULL,NULL,'2026-03-06','2026-03-10 13:00:00',NULL,'adjudicado',1,0.00,0,NULL,1,365,NULL,NULL,NULL,'https://www.compraspublicas.gob.ec/ProcesoContratacion/compras/NCO/NCORegistroDetalle.cpe?&id=jtNeJxsIeuuNoIrbT3A7tUSNEeZ-y3OmRvnlUoMPtTM,&op=0',1,NULL,'2026-03-09 04:03:34','2026-03-09 04:01:00','2026-03-09 04:03:34',NULL,1),(5,1,'NIC-1768186540001-2026-00004','infima_cuantia','Contratación del Servicio de Hosting parael CNIMH','979901011',NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,4,0.00,NULL,'USD',0,NULL,NULL,'2026-03-06','2026-03-09 10:12:00',NULL,'en_ejecucion',1,0.00,0,NULL,1,365,NULL,NULL,NULL,'https://www.compraspublicas.gob.ec/ProcesoContratacion/compras/NCO/NCORegistroDetalle.cpe?&id=-8al73464nzl0pHKA9Et5yxlRZKgt7LC8VpHSyhPQgw,&op=0',1,NULL,'2026-03-09 13:00:56','2026-03-09 04:05:55','2026-03-09 13:00:56',NULL,1),(6,1,'NIC-1768186540001-2026-00004','infima_cuantia','Contratación del Servicio de Hosting parael CNIMH','979901011',NULL,NULL,'SERVICIO ESPERADO\r\nEl Consejo Nacional para la Igualdad de la Movilidad Humana requiere contar con el servicio de\r\nhosting institucional, bajo las siguientes características:\r\nITEM CPC\r\nOBJETO DE\r\nCONTRATACIÓN\r\nCARACTERÍSTICAS, REQUISITOS\r\nFUNCIONALES O TECNOLÓGICOS UNIDAD CANTIDAD\r\n1 979901011\r\nCONTRATACION DEL\r\nSERVICIO DE HOSTING\r\nPARA EL CNIMH\r\n• SISTEMA OPERATIVO: Linux Centos 7 o\r\nsuperior\r\n• VERSIÓN PHP: 7.2 o superior\r\n• SERVIDOR WEB: APACHE 2.4 o superior\r\n• PANEL DE CONTROL: SI\r\n• PÁGINAS QUE SOPORTA: HTML, .HTM,\r\nPHP, .JAVA, FLASH\r\n• BASE DE DATOS: MySql 15.1 Distrib\r\n10.3.17 –Mariadb para Linux o superior\r\n• NÚMERO DE BASE DE DATOS: 1\r\n• ACCESO VÍA FTP: SI\r\n• NRO. CUENTAS FTP: 1\r\n• ESPACIO EN DISCO: 10 GB\r\n• ESTADÍSTICAS DE NAVEGACIÓN DEL\r\nSITIO: SI',1,NULL,'METODOLOGÍA DE TRABAJO\r\nPara cumplir con el servicio requerido, el Consejo Nacional para la Igualdad de Movilidad Humana\r\nrequiere al menos la siguiente metodología:\r\n• El CNIMH notificará al contratista la Orden de Compra suscrita.\r\n• El CNIMH designará a un servidor en calidad de Administrador/a de la Orden de Compra, quien\r\nserá responsable de coordinar las actividades necesarias relacionadas con el objeto de la\r\ncontratación. De igual manera, el proveedor adjudicado deberá designar a un asesor o responsable\r\ncon funciones equivalentes, que actuará como punto focal para la gestión conjunta del servicio, así\r\ncomo al equipo técnico encargado de la ejecución y entrega de los servicios contratados\r\n• El asesor brindará la información necesaria, alcance e interpretación de las condiciones técnicas\r\ngenerales y aplicables al servicio.\r\n• El /la Administrador/a de la Orden de Compra por parte del CNIMH entregará la información para\r\nlas facilidades a realizar por la empresa adjudicada para la activación y/o configuración del servicio,\r\nya sea de manera presencial o remota.\r\n• El equipo técnico designado por el contratista realizará la respectiva activación y/o configuración\r\ndel servicio de Hosting; se realizarán las pruebas de activación y funcionamiento que asegure el\r\ncumplimiento del servicio requerido. El contratista entregará el acta de entrega recepción del\r\nservicio\r\n• Una vez, se confirme la activación y funcionamiento del servicio de hosting se procederá a la\r\nsuscripción del Acta de Entrega Recepción Parcial.\r\n• Culminada la vigencia de la suscripción de 24 meses se suscribirá el Acta de Entrega Recepción\r\nDefinitiva entre el /la Administrador/a de la Orden de Compra y gestor de contrato designado por la\r\nContratista\r\n• Aplica Soporte técnico 24*7*365 días del año, SLA.','60','CÓDIGO CPC: (Clasificador Central de Productos)Para la “CONTRATACION DEL SERVICIO DE HOSTING PARA EL CNIMH” el proceso se\r\nenmarca en el código CPC 979901011 denominado “SOFTWARE Y HOSTING ESTRATEGICO\r\nPARA LA IMPLANTACION CON SOSTENIBILIDAD DE LA CALIDAD”, acorde al listado de CPC\r\nemitido por el SERCOP.',4,580.00,NULL,'USD',730,NULL,NULL,'2026-03-06','2026-03-09 10:12:00',NULL,'en_ejecucion',2,0.00,0,NULL,1,365,NULL,NULL,NULL,'https://www.compraspublicas.gob.ec/ProcesoContratacion/compras/NCO/NCORegistroDetalle.cpe?&id=f0NsoTlaFYqOKaUCCDP48rgS2VufaWF05MaVqJrGuy0,&op=0',1,NULL,'2026-03-09 22:37:07','2026-03-09 12:46:55','2026-03-09 22:37:07',NULL,1),(7,1,'NIC-1360055450001-2026-00002','infima_cuantia','SERVICIO DE ARRENDAMIENTO DE OFICINAS PARA LA FISCALÍA PROVINCIAL DE MANABÍ EN EL CANTÓN SANTA ANA','721120011',NULL,NULL,'<figure class=\"table\"><table><tbody><tr><td>ITEM</td><td><p>CPC</p><p>&nbsp;</p></td><td><p>OBJETO DE</p><p>&nbsp;</p><p>CONTRATACIÓN</p><p>&nbsp;</p></td><td><p>CARACTERÍSTICAS, REQUISITOS</p><p>&nbsp;</p><p>FUNCIONALES O TECNOLÓGICOS</p></td><td>UNIDAD</td><td><p>CANTIDAD</p><p>&nbsp;</p></td></tr><tr><td>1</td><td><p>979901011</p><p>&nbsp;</p></td><td><p>CONTRATACION DEL</p><p>&nbsp;</p><p>SERVICIO DE HOSTING</p><p>&nbsp;</p><p>PARA EL CNIMH</p><p>&nbsp;</p></td><td><p>• SISTEMA OPERATIVO: Linux Centos 7 o</p><p>&nbsp;</p><p>superior</p><p>&nbsp;</p><p>• VERSIÓN PHP: 7.2 o superior</p><p>&nbsp;</p><p>• SERVIDOR WEB: APACHE 2.4 o superior</p><p>&nbsp;</p><p>• PANEL DE CONTROL: SI</p><p>&nbsp;</p><p>• PÁGINAS QUE SOPORTA: HTML, .HTM,</p><p>&nbsp;</p><p>PHP, .JAVA, FLASH</p><p>&nbsp;</p><p>• BASE DE DATOS: MySql 15.1 Distrib</p><p>&nbsp;</p><p>10.3.17 –Mariadb para Linux o superior</p><p>&nbsp;</p><p>• NÚMERO DE BASE DE DATOS: 1</p><p>&nbsp;</p><p>• ACCESO VÍA FTP: SI</p><p>&nbsp;</p><p>• NRO. CUENTAS FTP: 1</p><p>&nbsp;</p><p>• ESPACIO EN DISCO: 10 GB</p><p>&nbsp;</p><p>• ESTADÍSTICAS DE NAVEGACIÓN DEL</p><p>&nbsp;</p><p>SITIO: SI</p><p>&nbsp;</p></td><td>unidad</td><td>1</td></tr></tbody></table></figure><p><br>&nbsp;</p>',1,NULL,NULL,NULL,NULL,5,0.00,NULL,'USD',0,NULL,NULL,'2026-03-09','2026-03-17 09:15:00',NULL,'adjudicado',2,0.00,0,NULL,1,365,NULL,NULL,NULL,'https://www.compraspublicas.gob.ec/ProcesoContratacion/compras/NCO/NCORegistroDetalle.cpe?&id=UJhi3mynMINPyQnAxZF6t8acoY9CgXp23cGD-2w-hj8,&op=0',1,NULL,'2026-03-09 22:36:55','2026-03-09 13:19:36','2026-03-09 22:36:55',NULL,1),(8,1,'NIC-1768045640001-2026-00019','infima_cuantia','Adquisición de equipos informáticos para el CB-C-SMB','624840012',NULL,NULL,NULL,1,NULL,N